import java.lang.reflect.Method;

public class GsonToJsonTest {

    private Gson gson;

    @BeforeEach
    public void setUp() {
        gson = new Gson();
    }

    @Test
    public void testToJson_NullSource_ReturnsJsonNull() throws Exception {
        // Using reflection to invoke private toJson(JsonElement) method
        Method toJsonJsonElementMethod = Gson.class.getDeclaredMethod("toJson", com.google.gson.JsonElement.class);
        toJsonJsonElementMethod.setAccessible(true);

        // When src is null, toJson should return toJson(JsonNull.INSTANCE)
        String expected = (String) toJsonJsonElementMethod.invoke(gson, JsonNull.INSTANCE);
        String actual = gson.toJson(null);

        assertEquals(expected, actual);
    }

    @Test
    public void testToJson_NonNullSource_ReturnsJsonString() {
        String src = "test string";
        String json = gson.toJson(src);
        assertEquals("\"test string\"", json);
    }

    @Test
    public void testToJson_PrimitiveInteger() {
        int src = 123;
        String json = gson.toJson(src);
        assertEquals("123", json);
    }

    @Test
    public void testToJson_ComplexObject() {
        TestClass obj = new TestClass();
        obj.id = 1;
        obj.name = "abc";
        String json = gson.toJson(obj);
        assertTrue(json.contains("\"id\":1"));
        assertTrue(json.contains("\"name\":\"abc\""));
    }

    static class TestClass {
        int id;
        String name;
    }
}
